@@ -0,0 +1,12 @@
+#![no_main]
+use libfuzzer_sys::fuzz_target;
+use fr_persist::parse_aof_manifest;
+
+fuzz_target!(|data: &[u8]| {
+    if data.len() > 1_000_000 {
+        return;
+    }
+    if let Ok(s) = std::str::from_utf8(data) {
+        let _ = parse_aof_manifest(s);
+    }
+});
